:root {
  /* Color system */
  --color-primary-green: #009B3A;
  --color-primary-yellow: #FED100;

  --color-secondary-black: #000000;
  --color-secondary-red: #FF0000;

  --color-accent-white: #FFFFFF;
  --color-accent-purple: #7A1A7A;

  --color-neutral-white: #FFFFFF;
  --color-neutral-light: #F5F5F5;
  --color-neutral-dark: #333333;

  --color-semantic-success: #009B3A;
  --color-semantic-error: #D32F2F;
  --color-semantic-warning: #FFC107;
  --color-semantic-info: #1976D2;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Karla", Arial, sans-serif;
  --font-script: "Great Vibes", "Dancing Script", cursive;

  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --layout-max-width: 1200px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-dark);
  background-color: var(--color-neutral-light);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none;
}

.site-shell {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-neutral-light);
}

.site-main {
  flex: 1 0 auto;
}

.site-header {
  flex-shrink: 0;
}

/* =============================
   TOP NAVIGATION BAR
   ============================= */

.header-top-nav {
  background-color: var(--color-primary-green);
  border-bottom: 3px solid var(--color-secondary-black);
}

.nav-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
}

.nav-logo-text {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: var(--space-2) 0;
  white-space: nowrap;
}

.nav-logo-main {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: 18px;
  line-height: var(--line-height-tight);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--color-accent-white);
}

.nav-logo-sub {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 12px;
  line-height: 1.2;
  color: var(--color-primary-yellow);
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.primary-nav {
  flex: 1 1 auto;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
}

.nav-item {
  margin: 0;
}

.nav-link {
  display: block;
  padding: 12px 14px;
  font-family: var(--font-body);
  font-weight: var(--font-weight-semibold);
  font-size: 14px;
  color: var(--color-accent-white);
  text-transform: none;
  white-space: nowrap;
  transition: color 0.15s ease-in-out, background-color 0.15s ease-in-out;
}

.nav-link--active {
  color: var(--color-primary-yellow);
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-primary-yellow);
  background-color: rgba(0, 0, 0, 0.15);
}

/* =============================
   HEADER BANNER (FLAG / HERO)
   ============================= */

.header-banner {
  position: relative;
  background-color: var(--color-secondary-black);
  /* Use a photographic flag texture when available to match the flyer-style hero */
  background-image: url("images/jamaican-flag-texture.jpg");
  background-size: cover;
  background-position: center;
  border-top: 4px solid var(--color-primary-green);
  border-bottom: 4px solid var(--color-primary-green);
  overflow: hidden;
}

/* Darken the flag slightly for legible text overlay */
.header-banner-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to bottom,
    rgba(0, 0, 0, 0.4) 0%,
    rgba(0, 0, 0, 0.6) 40%,
    rgba(0, 0, 0, 0.6) 60%,
    rgba(0, 0, 0, 0.4) 100%
  );
}

.header-banner-inner {
  position: relative;
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

/* Left logo block mimicking the emblem style */
.header-logo-panel {
  flex: 0 0 auto;
}

.header-logo-emblem {
  padding: 10px 18px;
  background: linear-gradient(to bottom, #000000 0%, #222222 100%);
  border: 3px solid var(--color-primary-yellow);
  box-shadow: 0 0 0 3px var(--color-secondary-black);
  text-align: center;
}

.logo-line {
  display: block;
  text-transform: uppercase;
}

.logo-line--top {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 11px;
  letter-spacing: 0.16em;
  color: var(--color-accent-white);
}

.logo-line--main {
  margin-top: 2px;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: 20px;
  letter-spacing: 0.08em;
  color: var(--color-primary-yellow);
  text-shadow: 1px 1px 0 var(--color-secondary-black), 2px 2px 0 var(--color-secondary-red);
}

.logo-line--bottom {
  margin-top: 4px;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 10px;
  letter-spacing: 0.18em;
  color: var(--color-accent-white);
}

/* Right hero text block on a black wedge, echoing the poster style */
.header-hero-panel {
  flex: 1 1 auto;
  max-width: 520px;
  margin-left: auto;
  padding: var(--space-4) var(--space-5);
  background-color: rgba(0, 0, 0, 0.92);
  color: var(--color-accent-white);
  text-align: right;
  /* Create arrow/wedge shape similar to the original design */
  clip-path: polygon(14% 0, 100% 0, 100% 100%, 0 100%);
}

.hero-kicker {
  margin: 0 0 4px 0;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 14px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-primary-yellow);
}

.hero-title {
  margin: 0;
  font-family: var(--font-script);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-regular);
  color: var(--color-accent-white);
}

.hero-tagline {
  margin: 6px 0 0 0;
  font-family: var(--font-body);
  font-size: 15px;
  line-height: var(--line-height-normal);
  color: var(--color-neutral-white);
}

/* =============================
   FOOTER
   ============================= */

.site-footer {
  flex-shrink: 0;
  background-color: var(--color-secondary-black);
  color: var(--color-accent-white);
  margin-top: var(--space-6);
}

.footer-stripe {
  height: 4px;
}

.footer-stripe--green {
  background-color: var(--color-primary-green);
}

.footer-stripe--yellow {
  background-color: var(--color-primary-yellow);
}

.footer-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-3) var(--space-4);
}

.footer-brand {
  margin-bottom: var(--space-4);
}

.footer-title {
  margin: 0 0 4px 0;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
  color: var(--color-primary-yellow);
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.footer-tagline {
  margin: 0;
  font-size: 15px;
  line-height: var(--line-height-relaxed);
  color: var(--color-neutral-white);
}

.footer-nav {
  margin-top: var(--space-2);
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2) var(--space-4);
}

.footer-item {
  margin: 0;
}

.footer-link {
  font-family: var(--font-body);
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-medium);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-accent-white);
  border-bottom: 1px solid transparent;
  padding-bottom: 2px;
  transition: color 0.15s ease-in-out, border-color 0.15s ease-in-out;
}

.footer-link:hover,
.footer-link:focus {
  color: var(--color-primary-yellow);
  border-color: var(--color-primary-yellow);
}

.footer-copy {
  margin: var(--space-4) 0 0 0;
  font-size: 12px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.7);
}

/* =============================
   RESPONSIVE ADJUSTMENTS
   ============================= */

@media (max-width: 960px) {
  .nav-inner {
    flex-wrap: wrap;
  }

  .nav-logo-text {
    padding-bottom: 0;
  }

  .primary-nav {
    width: 100%;
  }

  .nav-list {
    justify-content: center;
  }

  .header-banner-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .header-logo-panel {
    align-self: center;
  }

  .header-hero-panel {
    max-width: 100%;
    margin-left: 0;
    text-align: left;
    clip-path: none;
    padding: var(--space-3) var(--space-3);
  }
}

@media (max-width: 640px) {
  .nav-inner {
    padding-inline: var(--space-2);
  }

  .nav-logo-main {
    font-size: 16px;
  }

  .nav-logo-sub {
    font-size: 10px;
  }

  .nav-link {
    padding: 8px 10px;
    font-size: 13px;
  }

  .header-banner-inner {
    padding-inline: var(--space-2);
  }

  .hero-title {
    font-size: 30px;
  }

  .footer-inner {
    padding-inline: var(--space-2);
  }

  .footer-links {
    flex-direction: column;
    align-items: flex-start;
  }
}
